#include <stdio.h>

int main() {
    int T, G, I, Q;
    long long N, ans;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &G);
        while (G--) {
            scanf("%d %lld %d", &I, &N, &Q);
            if (N % 2 == 0) {
                ans = N / 2;
            } else {
                if (I == Q) ans = N / 2;          // floor(N/2)
                else        ans = N / 2 + 1;      // ceil(N/2)
            }
            printf("%lld\n", ans);
        }
    }
    return 0;
}

