import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        G = int(next(it))
        for _ in range(G):
            I = int(next(it))
            N = int(next(it))
            Q = int(next(it))
            if N % 2 == 0:
                ans = N // 2
            else:
                if I == Q:
                    ans = N // 2          # floor
                else:
                    ans = N // 2 + 1      # ceil
            out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

